from typing import List, Dict, Any, Optional, Callable
from leann.api import SearchResult
from leann.metadata_filter import MetadataFilterEngine
from collections import defaultdict


def apply_dynamic_filters(
    search_results: List[SearchResult],
    filter_specs: Dict[str, Dict[str, Any]],
    filter_logic: str = "AND"
) -> List[SearchResult]:
    """Apply dynamic metadata filters to search results with configurable logic.

    Args:
        search_results: List of SearchResult objects to filter
        filter_specs: Dictionary of filter specifications.
            Format: {"field_name": {"operator": value}}
            Example: {"category": {"==": "tech"}, "rating": {">=": 4.0}}
        filter_logic: "AND" (all filters must match) or "OR" (any filter matches)

    Returns:
        Filtered list of SearchResult objects
    """
    if not search_results or not filter_specs:
        return search_results

    # Convert SearchResult objects to dictionaries for filtering
    result_dicts = []
    result_mapping = {}

    for idx, result in enumerate(search_results):
        # Convert SearchResult to dictionary format
        # Assuming SearchResult has a to_dict() method or similar interface
        if hasattr(result, 'to_dict'):
            result_dict = result.to_dict()
        else:
            # Fallback: convert object attributes to dictionary
            result_dict = {attr: getattr(result, attr) for attr in dir(result) 
                          if not attr.startswith('_') and not callable(getattr(result, attr))}

        result_dicts.append(result_dict)
        result_mapping[idx] = result

    # Create MetadataFilterEngine instance
    filter_engine = MetadataFilterEngine()

    # Build filter conditions
    conditions = []
    for field_name, operator_dict in filter_specs.items():
        for operator, value in operator_dict.items():
            conditions.append({
                'field': field_name,
                'operator': operator,
                'value': value
            })

    # Apply filters based on logic
    if filter_logic.upper() == "AND":
        # AND logic: results must match all conditions
        filtered_indices = set(range(len(result_dicts)))

        for condition in conditions:
            current_filtered = filter_engine.apply_filter(result_dicts, [condition])
            current_indices = set(idx for idx, _ in enumerate(result_dicts) 
                                if idx in [i for i, _ in enumerate(current_filtered) if current_filtered[i]])

            filtered_indices = filtered_indices.intersection(current_indices)

    elif filter_logic.upper() == "OR":
        # OR logic: results must match at least one condition
        filtered_indices = set()

        for condition in conditions:
            current_filtered = filter_engine.apply_filter(result_dicts, [condition])
            current_indices = set(idx for idx, _ in enumerate(result_dicts) 
                                if idx in [i for i, _ in enumerate(current_filtered) if current_filtered[i]])

            filtered_indices = filtered_indices.union(current_indices)

    else:
        raise ValueError(f"Unsupported filter logic: {filter_logic}. Use 'AND' or 'OR'")

    # Convert back to SearchResult objects
    filtered_results = []
    for idx in sorted(filtered_indices):
        filtered_results.append(result_mapping[idx])

    return filtered_results

